import math
from dataclasses import dataclass

@dataclass
class TaskResult:
    task_id: str
    outcome_ok: bool          # objective check, when available
    judge_score: float        # 0..1 from an LLM judge, for open-ended output
    steps: int                # trajectory length (efficiency proxy)

def wilson_interval(k, n, z=1.96):
    """Wilson score interval — better than normal approx for small n / extreme p."""
    if n == 0:
        return (0.0, 1.0)
    p = k / n
    denom = 1 + z*z/n
    center = (p + z*z/(2*n)) / denom
    half = (z * math.sqrt(p*(1-p)/n + z*z/(4*n*n))) / denom
    return (max(0.0, center - half), min(1.0, center + half))

def aggregate(results):
    n = len(results)
    k = sum(r.outcome_ok for r in results)
    lo, hi = wilson_interval(k, n)
    return {
        "success_rate": round(k / n, 3) if n else None,
        "ci95": (round(lo, 3), round(hi, 3)),
        "mean_judge": round(sum(r.judge_score for r in results) / n, 3),
        "mean_steps": round(sum(r.steps for r in results) / n, 1),
    }
